package com.example.debug.grpc;

import java.time.Instant;
import java.util.LinkedHashMap;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

/**
 * Tracks internal state for debugging purposes.
 * In production, this captures the state of the service at the time of an error.
 */
public class InternalStateTracker {

    private final Map<String, String> state = new ConcurrentHashMap<>();
    private final String requestId;
    private final Instant startTime;

    public InternalStateTracker(String requestId) {
        this.requestId = requestId;
        this.startTime = Instant.now();
        state.put("request_id", requestId);
        state.put("start_time", startTime.toString());
        state.put("hostname", getHostname());
        state.put("thread_name", Thread.currentThread().getName());
        state.put("jvm_free_memory_mb", String.valueOf(Runtime.getRuntime().freeMemory() / (1024 * 1024)));
        state.put("jvm_total_memory_mb", String.valueOf(Runtime.getRuntime().totalMemory() / (1024 * 1024)));
    }

    public void track(String key, String value) {
        state.put(key, value);
    }

    public void trackPhase(String phase) {
        state.put("current_phase", phase);
        state.put("phase_timestamp", Instant.now().toString());
    }

    public Map<String, String> getState() {
        Map<String, String> snapshot = new LinkedHashMap<>(state);
        snapshot.put("elapsed_ms", String.valueOf(
                java.time.Duration.between(startTime, Instant.now()).toMillis()));
        return snapshot;
    }

    private static String getHostname() {
        try {
            return java.net.InetAddress.getLocalHost().getHostName();
        } catch (Exception e) {
            return "unknown";
        }
    }
}


