package com.example.debug.grpc;

import java.sql.SQLException;
import java.util.HashMap;
import java.util.Map;

/**
 * Simulates a database for demonstration purposes.
 */
public class FakeDatabase {

    private static final Map<String, Map<String, String>> USERS = new HashMap<>();
    private static final String CONNECTION_INFO = "jdbc:postgresql://db-prod-01:5432/userdb?user=app_user&pool_size=20";

    static {
        Map<String, String> user1 = new HashMap<>();
        user1.put("name", "Alice Johnson");
        user1.put("email", "alice@example.com");
        USERS.put("user-001", user1);

        Map<String, String> user2 = new HashMap<>();
        user2.put("name", "Bob Smith");
        user2.put("email", "bob@example.com");
        USERS.put("user-002", user2);
    }

    public Map<String, String> findUserById(String userId) throws SQLException {
        if ("user-error".equals(userId)) {
            throw new SQLException(
                    "ERROR: connection to server at \"db-prod-01\" (10.0.1.5), port 5432 failed: " +
                            "FATAL: too many connections for role \"app_user\"",
                    "08006", 53300);
        }

        if ("user-timeout".equals(userId)) {
            SQLException rootCause = new SQLException("Lock wait timeout exceeded; try restarting transaction");
            throw new SQLException(
                    "ERROR: could not execute query: SELECT * FROM users WHERE id = '" + userId + "'",
                    "57014", 57014, rootCause);
        }

        return USERS.get(userId);
    }

    public String processOrder(String orderId, String userId, double amount) throws SQLException {
        if (amount > 10000) {
            throw new SQLException(
                    "ERROR: new row for relation \"orders\" violates check constraint \"orders_amount_check\" " +
                            "DETAIL: Failing row contains (" + orderId + ", " + userId + ", " + amount + ")",
                    "23514", 0);
        }

        if ("order-deadlock".equals(orderId)) {
            SQLException rootCause = new SQLException(
                    "deadlock detected\nDETAIL: Process 12345 waits for ShareLock on transaction 67890; " +
                            "blocked by process 54321.");
            throw new SQLException("Transaction failed due to deadlock", "40P01", 0, rootCause);
        }

        return "CONFIRMED";
    }

    public String getConnectionInfo() {
        return CONNECTION_INFO;
    }
}


